import socket
import threading
import json
import math

class GameServer:
    def __init__(self, host='localhost', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((host, port))
        self.server_socket.listen()
        self.clients = {}
        self.lock = threading.Lock()

    def start(self):
        print("Server started, waiting for connections...")
        while True:
            client_socket, addr = self.server_socket.accept()
            print(f"Connection from {addr}")
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

    def handle_client(self, client_socket):
        try:
            while True:
                data = client_socket.recv(1024).decode('utf-8')
                if not data:
                    break
                self.process_data(client_socket, data)
        finally:
            self.remove_client(client_socket)

    def process_data(self, client_socket, data):
        try:
            message = json.loads(data)
            if 'action' not in message or 'player_id' not in message:
                return
            action = message['action']
            player_id = message['player_id']
            if action == 'update_position':
                self.update_player_position(player_id, message['position'])
            elif action == 'request_state':
                self.send_game_state(client_socket, player_id)
        except json.JSONDecodeError:
            pass

    def update_player_position(self, player_id, position):
        with self.lock:
            self.clients[player_id] = position
            self.broadcast_positions()

    def send_game_state(self, client_socket, player_id):
        with self.lock:
            player_position = self.clients.get(player_id)
            if player_position:
                visible_players = self.get_visible_players(player_position)
                client_socket.sendall(json.dumps(visible_players).encode('utf-8'))

    def get_visible_players(self, player_position):
        visible_players = {}
        for pid, pos in self.clients.items():
            if self.is_visible(player_position, pos):
                visible_players[pid] = pos
        return visible_players

    def is_visible(self, player_pos, other_pos):
        distance = math.sqrt((player_pos[0] - other_pos[0]) ** 2 + (player_pos[1] - other_pos[1]) ** 2)
        return distance < 100  # Example visibility range

    def broadcast_positions(self):
        for client_socket in self.clients.values():
            try:
                client_socket.sendall(json.dumps(self.clients).encode('utf-8'))
            except Exception:
                pass

    def remove_client(self, client_socket):
        with self.lock:
            for player_id, socket in list(self.clients.items()):
                if socket == client_socket:
                    del self.clients[player_id]
                    break
            client_socket.close()

if __name__ == "__main__":
    server = GameServer()
    server.start()